mapper.select:
SELECT FROM pm_lease l INNER JOIN property p ON p.id = l.property_id INNER JOIN tower tw ON tw.id = l.tower_id INNER JOIN unit_master u ON u.id = l.unit_id INNER JOIN customer c ON c.id = l.customer_id LEFT JOIN ( SELECT lease_id, COUNT(*) AS total_lease_units, SUM(area) AS total_lease_area, SUM(rent) AS total_rent, SUM(deposit) AS total_deposit, SUM(additional_charges + tax) AS total_charges FROM pm_lease_unit WHERE is_deleted = FALSE GROUP BY lease_id ) lu ON lu.lease_id = l.id WHERE l.is_deleted = FALSE
AND ( LOWER(l.lease_number) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(p.property_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(c.customer_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(u.unit_code) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(l.lease_status) LIKE CONCAT('%', LOWER(#{search}), '%') )
AND l.lease_status = #{leaseStatus}
AND l.renewal_status = #{renewalStatus}
ORDER BY l.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM pm_lease l INNER JOIN property p ON p.id = l.property_id INNER JOIN unit_master u ON u.id = l.unit_id INNER JOIN customer c ON c.id = l.customer_id WHERE l.is_deleted = FALSE
AND ( LOWER(l.lease_number) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(p.property_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(c.customer_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(u.unit_code) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(l.lease_status) LIKE CONCAT('%', LOWER(#{search}), '%') )
AND l.lease_status = #{leaseStatus}
AND l.renewal_status = #{renewalStatus}

SELECT COUNT(*)
FROM pm_lease l
WHERE l.is_deleted = FALSE
  AND l.lease_status = 'ACTIVE'
  AND l.id != #{excludeId}
  AND COALESCE(l.fit_out_period_start, l.start_date) <= #{endDate}
  AND l.end_date >= #{effectiveStartDate}
  AND (
      l.unit_id = #{unitId}
      OR EXISTS (
          SELECT 1
          FROM pm_lease_unit lu
          WHERE lu.lease_id = l.id
            AND lu.unit_id = #{unitId}
            AND lu.is_deleted = FALSE
      )
  )

SELECT COUNT(*)
FROM reservation_unit ru
INNER JOIN reservation r ON r.id = ru.reservation_id
WHERE ru.unit_id = #{unitId}
  AND ru.is_deleted = FALSE
  AND r.is_deleted = FALSE
  AND ru.reservation_status IN ('DRAFT', 'RESERVED')
  AND r.reservation_status IN ('DRAFT', 'RESERVED')
  AND r.reservation_date <= #{endDate}
  AND r.expiry_date >= #{effectiveStartDate}

mapper.insert:
INSERT INTO pm_lease_unit (
    tenant_id, lease_id, property_id, unit_id, unit_number, area, rent, additional_charges, deposit, tax, fit_out_period, unit_lease_status
)
VALUES (
    1, #{leaseId}, #{propertyId}, #{unitId}, #{unitNumber}, #{area}, #{rent}, #{additionalCharges}, #{deposit}, #{tax}, #{fitOutPeriod}, #{unitLeaseStatus}
)

INSERT INTO pm_lease_transaction (
    tenant_id, lease_id, transaction_number, transaction_type, previous_version_number, new_version_number,
    transaction_status, effective_start_date, effective_end_date, revised_rent_amount, revised_security_deposit,
    target_unit_id, reason, notes, created_by
)
VALUES (
    1, #{leaseId}, #{transactionNumber}, #{request.transactionType}, #{previousVersionNumber}, #{newVersionNumber},
    #{request.transactionStatus}, #{request.effectiveStartDate}, #{request.effectiveEndDate}, #{request.revisedRentAmount}, #{request.revisedSecurityDeposit},
    #{request.targetUnitId}, #{request.reason}, #{request.notes}, #{request.createdBy}
)

mapper.sql:
WHERE u.is_deleted = FALSE
AND p.id = #{propertyId}
AND tw.id = #{towerId}

    AND (LOWER(u.unit_code) LIKE CONCAT('%', LOWER(#{unitSearch}), '%') OR LOWER(u.unit_name) LIKE CONCAT('%', LOWER(#{unitSearch}), '%'))

AND u.occupancy_status = #{occupancyStatus}

    AND EXISTS (
        SELECT 1
        FROM pm_lease lp
        WHERE lp.is_deleted = FALSE
          AND lp.unit_id = u.id
          AND lp.start_date <= #{leasePeriod}
          AND lp.end_date >= #{leasePeriod}
    )


    AND (
        NOT EXISTS (
            SELECT 1
            FROM pm_lease la
            WHERE la.is_deleted = FALSE
              AND la.lease_status IN ('ACTIVE', 'PENDING_APPROVAL', 'SUSPENDED', 'TERMINATION_REVIEW')
              AND la.unit_id = u.id
              AND COALESCE(la.fit_out_period_start, la.start_date) <= #{dateTo}
              AND la.end_date >= #{dateFrom}
        )
        OR EXISTS (
            SELECT 1
            FROM pm_lease lb
            WHERE lb.is_deleted = FALSE
              AND lb.unit_id = u.id
              AND COALESCE(lb.fit_out_period_start, lb.start_date) <= #{dateTo}
              AND lb.end_date >= #{dateFrom}
        )
    )


    AND NOT EXISTS (
        SELECT 1
        FROM pm_lease lc
        WHERE lc.is_deleted = FALSE
          AND lc.lease_status IN ('ACTIVE', 'PENDING_APPROVAL', 'SUSPENDED', 'TERMINATION_REVIEW')
          AND lc.unit_id = u.id
          AND COALESCE(lc.fit_out_period_start, lc.start_date) <= #{dateTo}
          AND lc.end_date >= #{dateFrom}
    )
    AND NOT EXISTS (
        SELECT 1
        FROM reservation_unit ru
        INNER JOIN reservation r ON r.id = ru.reservation_id
        WHERE ru.unit_id = u.id
          AND ru.is_deleted = FALSE
          AND r.is_deleted = FALSE
          AND ru.reservation_status IN ('DRAFT', 'RESERVED')
          AND r.reservation_status IN ('DRAFT', 'RESERVED')
          AND r.reservation_date <= #{dateTo}
          AND r.expiry_date >= #{dateFrom}
    )


    AND (
        EXISTS (
            SELECT 1
            FROM pm_lease ld
            WHERE ld.is_deleted = FALSE
              AND ld.lease_status IN ('ACTIVE', 'PENDING_APPROVAL', 'SUSPENDED', 'TERMINATION_REVIEW')
              AND ld.unit_id = u.id
              AND COALESCE(ld.fit_out_period_start, ld.start_date) <= #{dateTo}
              AND ld.end_date >= #{dateFrom}
        )
        OR EXISTS (
            SELECT 1
            FROM reservation_unit ru2
            INNER JOIN reservation r2 ON r2.id = ru2.reservation_id
            WHERE ru2.unit_id = u.id
              AND ru2.is_deleted = FALSE
              AND r2.is_deleted = FALSE
              AND ru2.reservation_status IN ('DRAFT', 'RESERVED')
              AND r2.reservation_status IN ('DRAFT', 'RESERVED')
              AND r2.reservation_date <= #{dateTo}
              AND r2.expiry_date >= #{dateFrom}
        )
    )
